package kotlinx.coroutines

import kotlin.test.*
import kotlin.time.Duration
import kotlin.time.Duration.Companion.milliseconds
import kotlin.time.Duration.Companion.nanoseconds

class DelayDurationRoundingTest {

    @Test
    fun testRoundsUpSubMillisecondPart() {
        val duration = 998.milliseconds + 902_752.nanoseconds
        assertEquals(999L, duration.toDelayMillis())
    }

    @Test
    fun testDoesNotRoundExactMilliseconds() {
        val duration = 998.milliseconds
        assertEquals(998L, duration.toDelayMillis())
    }

    @Test
    fun testRoundsUpWhenHasNanosecondsPastWholeMillis() {
        val duration = 1.milliseconds + 1.nanoseconds
        assertEquals(2L, duration.toDelayMillis())
    }

    @Test
    fun testMinimumPositiveDelayIsOneMillisecond() {
        assertEquals(1L, 1.nanoseconds.toDelayMillis())
    }

    @Test
    fun testNonPositiveDelaysAreZero() {
        assertEquals(0L, Duration.ZERO.toDelayMillis())
        assertEquals(0L, (-1).milliseconds.toDelayMillis())
    }

    @Test
    fun testInfiniteDelayMapsToForever() {
        assertEquals(Long.MAX_VALUE, Duration.INFINITE.toDelayMillis())
    }
}
"}

